// Filter out reviews already sent, then try to find customer phone from leads table
const reviews = $input.all().map(i => i.json);
const results = [];

for (const review of reviews) {
  // Skip if already sent referral SMS
  if (review.referral_sms_sent === true) continue;

  // Try to match author_name to a lead to get their phone number
  const authorName = (review.author_name || '').trim();
  if (!authorName) continue;

  // Search leads table by name (first_name + last_name or full name)
  let phone = null;
  try {
    const nameParts = authorName.split(' ');
    const firstName = nameParts[0] || '';
    const lastName = nameParts.slice(1).join(' ') || '';

    const searchUrl = `https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1/leads?first_name=ilike.${encodeURIComponent(firstName)}&last_name=ilike.${encodeURIComponent(lastName)}&select=phone`;

    const resp = await fetch(searchUrl, {
      headers: {
        'apikey': 'SUPABASE_ANON_KEY_PLACEHOLDER',
        'Authorization': 'Bearer SUPABASE_ANON_KEY_PLACEHOLDER'
      }
    });
    const leads = await resp.json();
    if (Array.isArray(leads) && leads.length > 0 && leads[0].phone) {
      phone = leads[0].phone;
    }
  } catch (e) {
    // Could not find phone — skip this review
  }

  if (!phone) continue;

  results.push({
    json: {
      review_id: review.id,
      author_name: authorName,
      review_text: review.review_text,
      rating: review.rating,
      to_phone: phone
    }
  });
}

if (results.length === 0) {
  return [{ json: { _skip: true, reason: 'no_new_5star_reviews_with_phone' } }];
}

return results;

const d = $input.item.json;

if (d._skip) {
  return [{ json: d }];
}

const firstName = (d.author_name || 'there').split(' ')[0];

const messageBody = `Hi ${firstName}! Thank you SO much for your amazing 5-star review! It means the world to us. Know someone who needs yard care? Send them our way and we'll thank you with a discount on your next service! Just have them mention your name when they call (608) 535-6057 or visit tgyardcare.com. — TotalGuard`;

return [{ json: {
  review_id: d.review_id,
  author_name: d.author_name,
  to_phone: d.to_phone,
  message_body: messageBody,
  workflow_name: 'TG-22',
  message_type: 'referral_request'
} }];
